/**
 * Helper function to calculate the total cost for a specific pattern of non-adjacent peaks.
 * @param {number[]} nums The input array.
 * @param {number} start_index The starting index (1 or 2) for the peaks.
 * @returns {number} The total cost required for this pattern.
 */
function calculate_cost(nums, start_index) {
    const n = nums.length;
    let total_cost = 0;

    // Iterate through potential peak indices i = start_index, start_index + 2, ... up to n - 2
    for (let i = start_index; i <= n - 2; i += 2) {
        // Since the chosen peaks are non-adjacent, their neighbors are not modified by the peak operation.
        const left_neighbor = nums[i - 1];
        const right_neighbor = nums[i + 1];

        // Required value must be strictly greater than both neighbors.
        // Required = max(L, R) + 1
        // Using Math.max for large numbers handled correctly by JS standard Number type (up to 2^53 - 1)
        const required = Math.max(left_neighbor, right_neighbor) + 1;

        // Cost is max(0, Required - Original_Value)
        const cost_i = Math.max(0, required - nums[i]);

        total_cost += cost_i;
    }
    return total_cost;
}

/**
 * Solves the problem by finding the minimum cost to achieve the maximum number of special indices.
 * @param {number[]} nums The input array.
 * @returns {number} The minimum total operation cost.
 */
function solve(nums) {
    const n = nums.length;

    if (n < 3) {
        return 0; 
    }

    // Calculate cost for pattern S1: peaks at 1, 3, 5, ...
    const cost1 = calculate_cost(nums, 1);

    // Determine if pattern S2 (peaks at 2, 4, 6, ...) is potentially optimal.
    // If N is odd, S1 achieves one more peak than S2, so S1 must be chosen.
    // If N is even, both patterns achieve the maximum number of peaks, so we compare costs.

    if (n % 2 !== 0) {
        // N is odd, S1 maximizes peaks.
        return cost1;
    } else {
        // N is even, both S1 and S2 maximize peaks.
        const cost2 = calculate_cost(nums, 2);
        return Math.min(cost1, cost2);
    }
}

